import { useEffect, useMemo, useState } from 'react';

export interface IndicatorData {
	left: number;
	width?: number | string;
	right?: number;
}

/**
 * инкапсулирует логику управления положением индикатора табов
 *
 * его рассчеты также использованы для работы анимации
 *
 * Для работы анимации элементу необходимо задать transition для свойств width, left и right,
 * а также логически управлять данными текущего и предыдущего табов, логика такая
 *
 * 1. При клике таб сразу становится текущим
 * 2. В этот момент индикатор займет все пространство между предыдущм и текущим табами, хук сам сделает математику и т.д
 * 3. Через определенное время (тайминг анимации) предыдущий таб тоже становиться текущим
 * 4. В этот момент индикатор станет размером с текущий таб
 * 5. Анимация завершена, вы восхитительны
 *
 * Обратите внимание на 2 важные вещи:
 *
 * 1. тайминг transition в css должен быть немного (примерно в полтора раза) больше задержки присваивания предыдущему табу данных целевого
 * это позволяет сделать анимацию менее линейной, т.к индикатор начинает "уходить" с изначального таба еще до того как дополз до целевого
 * 2. общий тайминг анимации будет равен сумме двух тамингов, т.к по факту размер изменяется 2 раза (сначала увеличивается, потом уменьшается),
 * но уменьшение начинается раньше чем закончится увеличение
 *
 * Также обработаны кейсы первой отрисовки (когда предыдущего таба еще нет) и отсутствия данных (когда вообще нет выбранного таба)
 *
 * @param currentTabElement див текущего выбранного таба
 * @param previousTabElement див предыдущего выбранного таба
 * @param tabsContainer див контейнера с табами
 * @param scrollLeft проскроленное слева расстояние, нужно для компенсации визуального положения таба
 *
 * @returns объект с данными для абсолютного позиционирования индикатора
 */
export const useTabsIndicator = (
	currentTabElement: HTMLDivElement,
	previousTabElement: HTMLDivElement,
	tabsContainer: HTMLDivElement | null,
	scrollLeft: number,
): IndicatorData => {
	// расстояние от левого края контейнера с табами до текущего выбранного таба
	const currentTabLeft = useMemo(() => currentTabElement?.offsetLeft ?? 0, [currentTabElement]);
	// ширина текущего выбранного таба
	const currentTabWidth = useMemo(() => currentTabElement?.offsetWidth ?? 0, [currentTabElement]);
	// расстояние от левого края контейнера с табами до предыдущего выбранного таба
	const previousTabLeft = useMemo(() => previousTabElement?.offsetLeft ?? 0, [previousTabElement]);
	// ширина предыдущего выбранного таба
	const previousTabWidth = useMemo(() => previousTabElement?.offsetWidth ?? 0, [previousTabElement]);
	// ширина контейнера с табами
	const [tabsContainerWidth, setTabsContainerWidth] = useState(0);

	// слушаем ресайз контейнера с табами
	// нужно на случай нахождения табов в сайдшите или любом другом элементе, который может менять размер
	useEffect(() => {
		if (tabsContainer) {
			const resizer = new ResizeObserver((entries: ResizeObserverEntry[]) => {
				for (const { contentRect } of entries) {
					setTabsContainerWidth(contentRect.width);
				}
			});

			resizer.observe(tabsContainer);

			return () => {
				resizer.unobserve(tabsContainer);
			};
		}
	}, [tabsContainer]);

	return useMemo<IndicatorData>(() => {
		// при первой отрисовке возвращаем четкие размеры, иначе при отрисовке
		// индикатор сначала займет всю доступную ширину, а потом уменьшиться, выглядит так себе
		if (!previousTabElement) {
			return {
				left: currentTabLeft - scrollLeft,
				width: currentTabWidth,
			};
		}
		// ВАЖНО: все расчеты делаются с компенсацией скролла
		// если предыдущий элемент находится слева
		if (previousTabLeft < currentTabLeft) {
			// левый край индикатора располагается по расположению предыдущего таба
			// правый край по правому краю текущего таба, но отступ считается от правого края контейнера, поэтому математика такая
			// ширина контейнера - расстояние от левого края контейнера до правого края таба = расстояние от правого края таба до правого края контейнера
			return {
				left: previousTabLeft - scrollLeft,
				width: 'auto',
				right: tabsContainerWidth - (currentTabLeft - scrollLeft + currentTabWidth),
			};
		}

		// если предыдущий элемент находится справа
		if (previousTabLeft > currentTabLeft) {
			// логика точно такая же как слева, только отзеркалена
			return {
				left: currentTabLeft - scrollLeft,
				width: 'auto',
				right: tabsContainerWidth - (previousTabLeft - scrollLeft + previousTabWidth),
			};
		}

		// если предыдущий и текущий таб равны (конечный стейт анимации)
		if (previousTabLeft === currentTabLeft) {
			// логика точно такая же как раньше, но все расчеты идут от размеров и положения текущего таба
			// в целом в этот момент без разницы, можно просто задублировать любой из предыдущих блоков
			// решил вынести отдельно для лучшей читаемости
			return {
				left: currentTabLeft - scrollLeft,
				width: 'auto',
				right: tabsContainerWidth - (currentTabLeft - scrollLeft + currentTabWidth),
			};
		}

		// по дефолту просто перемещаем индикатор к выбранному табу, задавая ему соответствующий размер
		// дефолтное значение currentTabLeft === 0, так что тут же обработаны крайние случаи
		// например при отсутствии выбранного таба индикатора просто не будет на экране т.к его ширина будет === 0
		return {
			left: currentTabLeft - scrollLeft,
			width: currentTabWidth,
		};
	}, [
		previousTabWidth,
		previousTabLeft,
		currentTabWidth,
		currentTabLeft,
		tabsContainerWidth,
		scrollLeft,
		previousTabElement,
	]);
};
